import{_ as h,o as t,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Tự động hóa","description":"","frontmatter":{"title":"Tự động hóa","sidebar_position":7},"headers":[],"relativePath":"automation.md","filePath":"automation.md"}'),o={name:"automation.md"};function c(e,n,g,l,u,r){return t(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="tu-đong-hoa" tabindex="-1">Tự động hóa <a class="header-anchor" href="#tu-đong-hoa" aria-label="Permalink to &quot;Tự động hóa&quot;">​</a></h1><p>Mô-đun Tự động hóa trong ABNERP giúp doanh nghiệp tự động hóa các quy trình nghiệp vụ lặp đi lặp lại, tiết kiệm thời gian, giảm thiểu sai sót và nâng cao hiệu suất làm việc. Thay vì thực hiện thủ công các tác vụ hàng ngày, nhân viên có thể tập trung vào công việc có giá trị cao hơn.</p><h2 id="quy-tac-phan-cong-assignment-rules" tabindex="-1">Quy tắc phân công (Assignment Rules) <a class="header-anchor" href="#quy-tac-phan-cong-assignment-rules" aria-label="Permalink to &quot;Quy tắc phân công (Assignment Rules)&quot;">​</a></h2><p>Quy tắc phân công cho phép tự động gán tài liệu hoặc tác vụ cho nhân viên dựa trên các tiêu chí như: phòng ban, kỹ năng, khối lượng công việc hiện tại hoặc luân phiên. Ví dụ, đơn bán hàng từ khách hàng ở khu vực miền Bắc sẽ tự động được gán cho nhân viên kinh doanh phụ trách khu vực đó. Bạn có thể thiết lập nhiều quy tắc ưu tiên khác nhau để đảm bảo công việc được phân bổ hợp lý.</p><h2 id="tu-đong-lap-lai-auto-repeat" tabindex="-1">Tự động lặp lại (Auto Repeat) <a class="header-anchor" href="#tu-đong-lap-lai-auto-repeat" aria-label="Permalink to &quot;Tự động lặp lại (Auto Repeat)&quot;">​</a></h2><p>Tính năng tự động lặp lại cho phép tạo các bản ghi định kỳ theo lịch trình: tạo đơn mua hàng hàng tháng, phiếu bảo trì hàng tuần, hoặc báo giá định kỳ cho khách hàng thân thiết. Bạn có thể cấu hình tần suất lặp lại, số lần lặp, và thời điểm bắt đầu/kết thúc. Hệ thống sẽ tự động tạo bản ghi mới dựa trên mẫu đã định nghĩa trước.</p><h2 id="theo-doi-moc-milestone-tracking" tabindex="-1">Theo dõi mốc (Milestone Tracking) <a class="header-anchor" href="#theo-doi-moc-milestone-tracking" aria-label="Permalink to &quot;Theo dõi mốc (Milestone Tracking)&quot;">​</a></h2><p>Theo dõi mốc cho phép thiết lập các mốc quan trọng trong quy trình nghiệp vụ và tự động kích hoạt hành động khi đạt đến mốc. Ví dụ: khi đơn hàng đạt mốc &quot;Đã giao hàng&quot;, hệ thống tự động tạo hóa đơn và gửi email thông báo cho khách hàng. Bạn có thể theo dõi tiến độ hoàn thành các mốc qua dashboard trực quan.</p><h2 id="tu-đong-hoa-email-email-automation" tabindex="-1">Tự động hóa email (Email Automation) <a class="header-anchor" href="#tu-đong-hoa-email-email-automation" aria-label="Permalink to &quot;Tự động hóa email (Email Automation)&quot;">​</a></h2><p>ABNERP cho phép thiết lập các kịch bản gửi email tự động dựa trên sự kiện hoặc điều kiện: gửi email cảm ơn khi khách hàng đặt hàng, gửi nhắc nhở thanh toán khi hóa đơn đến hạn, hoặc gửi thông báo tồn kho thấp cho bộ phận thu mua. Email có thể được cá nhân hóa với thông tin khách hàng và dữ liệu từ hệ thống, giúp tăng hiệu quả truyền thông và chăm sóc khách hàng.</p>',10)])])}const s=h(o,[["render",c]]);export{m as __pageData,s as default};
